class Solution:
    def longestMountain(self, arr):
        n = len(arr)
        best = 0
        i = 1
        while i < n - 1:
            if arr[i - 1] < arr[i] > arr[i + 1]:
                l = i - 1
                while l > 0 and arr[l - 1] < arr[l]:
                    l -= 1
                r = i + 1
                while r < n - 1 and arr[r + 1] < arr[r]:
                    r += 1
                best = max(best, r - l + 1)
                i = r + 1
            else:
                i += 1
        return best

