var longestMountain = function(arr) {
    const n = arr.length;
    let best = 0;
    let i = 1;
    while (i < n - 1) {
        if (arr[i - 1] < arr[i] && arr[i] > arr[i + 1]) {
            let l = i - 1;
            while (l > 0 && arr[l - 1] < arr[l]) l--;
            let r = i + 1;
            while (r < n - 1 && arr[r + 1] < arr[r]) r++;
            best = Math.max(best, r - l + 1);
            i = r + 1;
        } else {
            i++;
        }
    }
    return best;
};
